INSERT INTO documents (section_slug, page_slug, title, content, updated_by)
VALUES (
  'affiliate',
  'operations',
  'Operations',
  $JSON${"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Affiliate Operations Workflow"}]},{"type":"paragraph","content":[{"type":"text","text":"Monthly Cycle · Payments · Disputes · Termination. Ongoing operational management covering the monthly commission processing cycle, payment disbursement, dispute resolution, fraud detection, and partner termination."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Monthly Commission Processing Cycle"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Day 1\u2013Last — Accrual Period: NGR accrues daily per player. CPA triggers record when FTD qualifications are met. Override chain calculates in real time in the portal."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Day 1\u20133 (Next Month) — Report Generation: CRM Analyst runs monthly commission report. All levels calculated. Negative carryover applied. Report locked — no further changes after Day 3."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Day 4\u20137 — Review & Dispute Window: Affiliates review their portal statement. Any disputes raised within this window are investigated. Adjustments approved by Affiliate Manager before payment run."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Day 8\u201315 — Commission Payment: Payments processed to affiliate's registered account. BIR withholding tax deducted at source. Payment confirmation sent. Finance team remits WHT to BIR."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Fraud Detection — Affiliate-Specific Patterns"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Affiliate Fraud Detection & Response (Zero Tolerance)"}]},{"type":"paragraph","content":[{"type":"text","text":"Fake traffic · Self-referral · Bonus stacking · Commission manipulation · Sub-affiliate fraud"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Fraud Signals to Monitor"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Self-referral: affiliate registers a player account using their own device, IP, or payment method and generates commissions on their own deposits. Cross-check all FTD qualifications against the affiliate's own KYC data"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Fake traffic / incentivised registration: affiliate pays third parties to register and make a small FTD to trigger CPA payouts, with no genuine intention to play. Indicators: very low deposit amounts at exactly the minimum threshold, immediate withdrawal after FTD, high FTD-to-churn rate"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Bonus abuse through referrals: affiliate sends players who are in coordinated bonus abuse rings. Monitor for high volumes of player referrals from a single affiliate who all claim the same promotion and never return"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Commission manipulation: affiliate with sub-affiliate recruitment rights creates fictitious sub-affiliates to generate override commissions without any real traffic being sent. Cross-reference sub-affiliate KYC against affiliate's own identity documents"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cookie stuffing: affiliate uses technical methods to drop tracking cookies on browsers of users who never saw or clicked an affiliate link — inflating attribution counts without genuine referrals"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Response Actions"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Affiliate Manager flags the suspicious pattern and raises a formal investigation case — do not immediately terminate without evidence"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Coordinate with the Fraud team (Tier 2 Senior Analyst) to review the player accounts associated with the affiliate's tracking links"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"If fraud is confirmed: withhold the current month's commission payment pending Head of Affiliates review. Do not inform the affiliate at this stage"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Head of Affiliates reviews evidence and makes the final call: (a) commission clawback and formal warning, (b) immediate termination with full clawback of all fraudulent commissions, or (c) legal action if scale warrants"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Clawback is applied to all commissions traceable to fraudulent activity — including override commissions paid to upstream levels if they were knowingly complicit. Document all clawback actions in the affiliate's CRM record"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Warning + Clawback: Minor or first-time violation. Commissions from fraudulent referrals reversed. Final warning issued in writing."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Termination + Full Clawback: Systematic fraud. Agreement terminated. All fraudulent commissions clawed back. Account permanently closed. Platform and tracking links deactivated."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Dispute Resolution Process"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Step 1 — Affiliate Raises Dispute: Via portal ticket within the 4-day dispute window. Must specify: month, amount disputed, reason, and supporting evidence."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Step 2 — Affiliate Manager Reviews: Checks portal reports against the CRM source data within 3 business days. Identifies any system error, tracking failure, or legitimate discrepancy."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Step 3 — Resolution & Adjustment: If valid: adjustment approved by Affiliate Manager, applied to next payment run. If rejected: written explanation sent with evidence. Affiliate may escalate to Head of Affiliates within 5 days."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Partner Termination"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Voluntary Termination"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Affiliate provides 30-day written notice via the portal or email to the Affiliate Manager"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"During the 30-day notice period: tracking links remain active, player attributions continue, and RevShare accrues normally"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Final commission statement issued within 15 days of the termination effective date. All earned and unpaid commissions paid in the final payment run"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Player attributions for direct referrals are retained by the operator — the terminated affiliate forfeits future RevShare on those players from the termination date"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"If the affiliate had active sub-affiliates: sub-affiliate contracts must be reviewed. Sub-affiliates may be migrated to direct L1 agreements with the operator at the Affiliate Manager's discretion"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Involuntary Termination (Breach)"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Immediate termination: fraud confirmed, PAGCOR marketing violations, KYC document forgery, or material breach of the affiliate agreement"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Tracking links deactivated immediately. Portal access suspended. No further commission accrual from termination date"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Pending commissions withheld pending clawback assessment. Any fraudulent commissions already paid are subject to recovery action"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Head of Affiliates approves all involuntary terminations. Legal team engaged if clawback value exceeds \u20b150,000 or if criminal activity is suspected"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Compliance team notified if termination is related to AML or KYC concerns — may trigger AMLC STR process if warranted"}]}]}]}]}$JSON$::jsonb,
  'system'
)
ON CONFLICT (section_slug, page_slug) DO UPDATE
  SET title = EXCLUDED.title,
      content = EXCLUDED.content,
      updated_at = NOW(),
      updated_by = EXCLUDED.updated_by;
